using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;
using System.Security.Cryptography;
using System.Text;

namespace MyApp.Controllers
{
    [ApiController]
    public class FileUploadController : ControllerBase
    {
        [HttpPost("upload")]
        public IActionResult UploadFile()
        {
            var file = Request.Form.Files[0];
            if (file == null)
            {
                return BadRequest();
            }

            // Check for insecure file types
            if (!IsSecureFileType(file.FileName))
            {
                return Forbid();
            }

            // Save the file to wwwroot/uploads directory
            var uploadsDirectory = Path.Combine(_env.WebRootPath, "uploads");
            var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
            var filePath = Path.Combine(uploadsDirectory, fileName);
            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                file.CopyTo(stream);
            }

            // Return the file path
            return Ok(new { filePath });
        }

        private bool IsSecureFileType(string fileName)
        {
            var secureFileTypes = new[] { ".jpg", ".jpeg", ".png", ".pdf", ".docx", ".xlsx" };
            return secureFileTypes.Any(t => fileName.EndsWith(t));
        }
    }
}